  /**
   * 安全地清理资源
   * @param {string} url - 需要释放的URL对象
   */
  static safeRevokeURL(url) {
    try {
      if (url && url.startsWith('blob:')) {
        URL.revokeObjectURL(url);
      }
    } catch (error) {
      console.warn('释放URL资源时出错:', error);
    }
  }

  /**
   * 生成简单的哈希字符串（浏览器兼容版本）
   * @param {string} str - 需要哈希的字符串
   * @returns {string} 哈希结果
   */
  static generateSimpleHash(str) {
    // 简单的字符串哈希函数实现（浏览器兼容）
    let hash = 0;
    if (str.length === 0) return 'SIU-' + Math.random().toString(36).substring(2, 10).toUpperCase();
    
    for (let i = 0; i < str.length; i++) {
      const char = str.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash; // 转换为32位整数
    }
    
    // 转换为16进制字符串并添加前缀
    const hashHex = Math.abs(hash).toString(16).toUpperCase();
    return 'SIU-' + hashHex.substring(0, 8);
  }

